/**
 * MedX describedby accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Aria-describedby wiring for errors.
 */
const DESCRIBEDBY_TOKENS = Object.freeze({
  primary: { value: "a11y-describedby-primary", scope: "a11y" },
  secondary: { value: "a11y-describedby-secondary", scope: "a11y" },
  muted: { value: "a11y-describedby-muted", scope: "a11y" },
  accent: { value: "a11y-describedby-accent", scope: "a11y" },
  surface: { value: "a11y-describedby-surface", scope: "a11y" },
});

const DESCRIBEDBY_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const DESCRIBEDBY_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const describedbyRegistry = new Map();
const DESCRIBEDBY_listeners = new Set();
let DESCRIBEDBY_seq = 0;

function createDescribedbyId(prefix = "medx-a11y-describedby") {
  DESCRIBEDBY_seq += 1;
  return `${prefix}-${DESCRIBEDBY_seq}`;
}

function registerDescribedby(config = {}) {
  const entryId = config.id ?? createDescribedbyId();
  const preset = DESCRIBEDBY_PRESETS[config.preset ?? "default"] ?? DESCRIBEDBY_PRESETS.default;
  const token = DESCRIBEDBY_TOKENS[config.token ?? preset.token] ?? DESCRIBEDBY_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: DESCRIBEDBY_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  describedbyRegistry.set(entryId, entry);
  notifyDescribedbyListeners("register", entry);
  return entry;
}

function updateDescribedby(id, patch = {}) {
  const entry = describedbyRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyDescribedbyListeners("update", entry);
  return entry;
}

function resolveDescribedby(id) {
  const entry = describedbyRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listDescribedbyEntries(filter = {}) {
  let items = Array.from(describedbyRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onDescribedbyEvent(listener) {
  DESCRIBEDBY_listeners.add(listener);
  return () => DESCRIBEDBY_listeners.delete(listener);
}

function notifyDescribedbyListeners(type, entry) {
  for (const listener of DESCRIBEDBY_listeners) {
    try {
      listener({ type, entry, registrySize: describedbyRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:describedby] listener error", err.message);
    }
  }
}

function getDescribedbyMetrics() {
  const items = listDescribedbyEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(DESCRIBEDBY_TOKENS).length,
    presets: Object.keys(DESCRIBEDBY_PRESETS).length,
  };
}

async function runMedxDescribedby() {
  console.log("[medx:ui:a11y:describedby] runtime initialized");
  console.log(`[medx:ui:a11y:describedby] tokens=${Object.keys(DESCRIBEDBY_TOKENS).length} presets=${Object.keys(DESCRIBEDBY_PRESETS).length}`);

  const events = [];
  onDescribedbyEvent((e) => events.push(e.type));

  const domains = Object.keys(DESCRIBEDBY_SUPPLY_CHAIN);
  const presets = Object.keys(DESCRIBEDBY_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerDescribedby({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/describedby" },
    });
  }

  const first = listDescribedbyEntries()[0];
  if (first) updateDescribedby(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getDescribedbyMetrics();
  const resolved = first ? resolveDescribedby(first.id) : null;

  console.log(`[medx:ui:a11y:describedby] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:describedby] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:describedby] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:describedby] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:describedby] bootstrap complete");
}

module.exports = runMedxDescribedby;
